package com.agc.bwitch.domain.rituals.i18n

import com.agc.bwitch.domain.localization.AppLanguage

object RitualCatalogContentRepository {

    private const val KEY_PREFIX = "ritual_catalog."

    fun resolve(language: AppLanguage, key: String): String {
        return localizedCatalog[language]?.get(key)
            ?: spanishCatalog[key]
            ?: key
    }

    fun resolveCompat(language: AppLanguage, value: String): String {
        return if (value.isRitualCatalogKey()) resolve(language = language, key = value) else value
    }

    fun String.isRitualCatalogKey(): Boolean = startsWith(KEY_PREFIX)

